function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const stars: number[] = [];
    let totalSubstrings = n * (n + 1) / 2;
    let currentNoStarSubstrings = totalSubstrings;

    for (let t = 0; t < n; t++) {
        const pos = order[t];
        // Find the insertion index
        let insertIndex = 0;
        while (insertIndex < stars.length && stars[insertIndex] < pos) {
            insertIndex++;
        }
        stars.splice(insertIndex, 0, pos);

        // Find left and right neighbors
        let left = -1;
        if (insertIndex > 0) {
            left = stars[insertIndex - 1];
        }
        let right = n;
        if (insertIndex < stars.length) {
            right = stars[insertIndex];
        }

        // Compute original contribution
        const originalGapLength = right - left - 1;
        const originalContribution = originalGapLength * (originalGapLength + 1) / 2;

        // Compute new contribution
        const leftGapLength = pos - left - 1;
        const rightGapLength = right - pos - 1;
        const newContribution = (leftGapLength * (leftGapLength + 1)) / 2 + (rightGapLength * (rightGapLength + 1)) / 2;

        // Update currentNoStarSubstrings
        currentNoStarSubstrings = currentNoStarSubstrings - originalContribution + newContribution;

        // Check if valid
        const validCount = totalSubstrings - currentNoStarSubstrings;
        if (validCount >= k) {
            return t;
        }
    }

    return -1;
}
